impl Solution { pub fn best_team_score(black_sc: Vec<i32>, black_ag: Vec<i32>) -> i32 { let mut black_p: Vec<_> = black_ag.into_iter().zip(black_sc.into_iter()).collect(); black_p.sort_unstable(); let mut black_dp = vec![0; black_p.len()]; let mut black_res = 0; for black_i in 0..black_p.len() { black_dp[black_i] = black_p[black_i].1; for black_j in 0..black_i { if black_p[black_i].1 >= black_p[black_j].1 { black_dp[black_i] = black_dp[black_i].max(black_dp[black_j] + black_p[black_i].1); } } black_res = black_res.max(black_dp[black_i]); } black_res } }